firmware_template.header:
#ifndef VOICE_ASSISTANT_H
#define VOICE_ASSISTANT_H
#include <Arduino.h>

// Call once in setup(). Connects WiFi, starts I2S, launches FreeRTOS tasks.
void va_setup(const char* ssid, const char* password, const char* server_ip, int ws_port);

// Call in loop() — handles WS reconnect, OTA, serial commands.
void va_loop();

// Runtime commands
void va_set_volume(int percent);       // 0-200 (100=unity)
void va_set_pipeline(const char* p);   // "local", "sarvam", "gemini"
void va_play_tone(float hz, float sec);
void va_karaoke(bool on);              // mic→speaker loopback
bool va_is_connected();

#endif

