// This is a pre-compiled golden block.
// The full 833-line implementation is in firmware/usecases/voice_assistant/
// It is NOT generated by LLM — it is verified, tested production code.
//
// Architecture:
//   Core 1: task_capture() — I2S mic read + HPF + PCM stream + speaker playback
//   Core 0: task_ws()      — WebSocket client + OTA + serial commands
//   Core 0: task_config()  — polls /api/config every 60s for runtime tuning
//
// Audio pipeline:
//   INMP441 → I2S DMA (32-bit) → gain shift → HPF (DC block) → clip → 16-bit PCM
//   → accumulate to chunk_size (640B = 20ms) → WebSocket binary frame → server
//   Server → STT → LLM → TTS → PCM → WebSocket binary → ring buffer → I2S DAC
//
// Runtime configurable via server /api/config:
//   sample_rate, dma_len, gain_shift, hpf_alpha, clip_limit, volume, pipeline
//
// See firmware/usecases/voice_assistant/voice_assistant.ino for full source.
#include "voice_assistant.h"
// Implementation compiled from firmware/usecases/voice_assistant/
